# Cartesian Product (A × B) - All ordered pairs
A = {1, 2}
B = {'x', 'y'}

# Method 1: Using iteration
cartesian = {(a, b) for a in A for b in B}
print(f"A × B = {cartesian}")
print(f"|A × B| = |A| × |B| = {len(A)} × {len(B)} = {len(cartesian)}")

# Set Builder Notation Examples
# Example 1: S = {x² | x ∈ ℕ, x < 5}
natural_numbers = {1, 2, 3, 4}
S = {x**2 for x in natural_numbers}
print(f"\n{{x² | x ∈ ℕ, x < 5}} = {S}")

# Example 2: Even numbers from 1-20 using set builder
E = {x for x in range(1, 21) if x % 2 == 0}
print(f"{{x | 1 ≤ x ≤ 20, x is even}} = {E}")

# Example 3: Set of tuples satisfying condition
# C = {(x,y) | x ∈ {1,2,3}, y ∈ {1,2,3}, x + y = 4}
C = {(x, y) for x in range(1, 4) for y in range(1, 4) if x + y == 4}
print(f"{{(x,y) | x+y=4, x,y∈{{1,2,3}}}} = {C}")

# De Morgan's Laws Verification
U = {1, 2, 3, 4, 5}  # Universal set
X = {1, 2}
Y = {2, 3, 4}

# De Morgan's Law: (X ∪ Y)' = X' ∩ Y'
left_side = U - (X | Y)  # (X ∪ Y)'
right_side = (U - X) & (U - Y)  # X' ∩ Y'

print(f"\nDe Morgan's Law Verification:")
print(f"(X ∪ Y)' = {left_side}")
print(f"X' ∩ Y' = {right_side}")
print(f"Law verified: {left_side == right_side}")
